tblSummaryBase <- if (requireNamespace("jmvcore", quietly=TRUE)) R6::R6Class(
    "tblSummaryBase",
    inherit = jmvcore::Analysis,
    public = list(
        initialize = function(options, data=NULL, datasetId="", analysisId="", revision=0) {
            super$initialize(
                package = "SummaryTables",
                name = "tblSummary",
                version = c(1,0,0),
                options = options,
                results = tblSummaryResults$new(options=options),
                data = data,
                datasetId = datasetId,
                analysisId = analysisId,
                revision = revision,
                pause = NULL,
                completeWhenFilled = FALSE,
                requiresMissings = FALSE,
                weightsSupport = 'auto')
        }))

#' Table Summary
#'
#' 
#' @param data .
#' @param varsCont .
#' @param varsCat .
#' @param groupBy .
#' @param missing .
#' @param missingText .
#' @param percent .
#' @param journal .
#' @param compact .
#' @param language .
#' @param boldLabels .
#' @param boldLevels .
#' @param italicizeLabels .
#' @param italicizeLevels .
#' @param sortCatDefault .
#' @param sortCatSpecific .
#' @param statContDefault .
#' @param statsContSpecific .
#' @param digitsCont .
#' @param statCatDefault .
#' @param statsCatSpecific .
#' @param digitsPct .
#' @param pValue .
#' @param digitsPvalue .
#' @param boldP .
#' @param boldPThreshold .
#' @param separatePFootnotes .
#' @param testContDefault .
#' @param testsContSpecific .
#' @param testCatDefault .
#' @param testsCatSpecific .
#' @param export .
#' @param path .
#' @return A results object containing:
#' \tabular{llllll}{
#'   \code{results$tbl} \tab \tab \tab \tab \tab a html \cr
#' }
#'
#' @export
tblSummary <- function(
    data,
    varsCont,
    varsCat,
    groupBy,
    missing = "ifany",
    missingText = "Unknown",
    percent = "column",
    journal = "none",
    compact = FALSE,
    language = "en",
    boldLabels = FALSE,
    boldLevels = FALSE,
    italicizeLabels = FALSE,
    italicizeLevels = FALSE,
    sortCatDefault = "alphanumeric",
    sortCatSpecific,
    statContDefault = "meanSd",
    statsContSpecific,
    digitsCont = "auto",
    statCatDefault = "nPercent",
    statsCatSpecific,
    digitsPct = "auto",
    pValue = FALSE,
    digitsPvalue = "auto",
    boldP = FALSE,
    boldPThreshold = 0.05,
    separatePFootnotes = FALSE,
    testContDefault = "parametric",
    testsContSpecific = list(),
    testCatDefault = "auto",
    testsCatSpecific = list(),
    export = FALSE,
    path = "~/Desktop/Summary Table.docx") {

    if ( ! requireNamespace("jmvcore", quietly=TRUE))
        stop("tblSummary requires jmvcore to be installed (restart may be required)")

    if ( ! missing(varsCont)) varsCont <- jmvcore::resolveQuo(jmvcore::enquo(varsCont))
    if ( ! missing(varsCat)) varsCat <- jmvcore::resolveQuo(jmvcore::enquo(varsCat))
    if ( ! missing(groupBy)) groupBy <- jmvcore::resolveQuo(jmvcore::enquo(groupBy))
    if (missing(data))
        data <- jmvcore::marshalData(
            parent.frame(),
            `if`( ! missing(varsCont), varsCont, NULL),
            `if`( ! missing(varsCat), varsCat, NULL),
            `if`( ! missing(groupBy), groupBy, NULL))


    options <- tblSummaryOptions$new(
        varsCont = varsCont,
        varsCat = varsCat,
        groupBy = groupBy,
        missing = missing,
        missingText = missingText,
        percent = percent,
        journal = journal,
        compact = compact,
        language = language,
        boldLabels = boldLabels,
        boldLevels = boldLevels,
        italicizeLabels = italicizeLabels,
        italicizeLevels = italicizeLevels,
        sortCatDefault = sortCatDefault,
        sortCatSpecific = sortCatSpecific,
        statContDefault = statContDefault,
        statsContSpecific = statsContSpecific,
        digitsCont = digitsCont,
        statCatDefault = statCatDefault,
        statsCatSpecific = statsCatSpecific,
        digitsPct = digitsPct,
        pValue = pValue,
        digitsPvalue = digitsPvalue,
        boldP = boldP,
        boldPThreshold = boldPThreshold,
        separatePFootnotes = separatePFootnotes,
        testContDefault = testContDefault,
        testsContSpecific = testsContSpecific,
        testCatDefault = testCatDefault,
        testsCatSpecific = testsCatSpecific,
        export = export,
        path = path)

    analysis <- tblSummaryClass$new(
        options = options,
        data = data)

    analysis$run()

    analysis$results
}

